/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;
    const INF = 1e18;

    if (k === 0) {
        return 0;
    }

    // Maximum possible peaks is floor(n/2)
    if (k > Math.floor(n / 2)) {
        return -1;
    }

    // 1. Calculate initial costs C_i
    const C = new Array(n);
    for (let i = 0; i < n; i++) {
        const prev = nums[(i - 1 + n) % n];
        const next = nums[(i + 1) % n];
        const required = Math.max(prev, next) + 1;
        C[i] = Math.max(0, required - nums[i]);
    }

    // 2. Handle N=2 case separately
    if (n === 2) {
        if (k === 1) {
            return Math.min(C[0], C[1]);
        }
        // k > 1 is already handled above
        return -1; 
    }

    /**
     * Solves the linear selection problem: find min cost to select target_k non-adjacent items
     * in the range [start_idx, end_idx].
     * 
     * @param {number} start_idx 
     * @param {number} end_idx 
     * @param {number} target_k 
     * @param {number[]} costs 
     * @returns {number} Minimum cost or INF
     */
    const solve_linear = (start_idx, end_idx, target_k, costs) => {
        const L = end_idx - start_idx + 1;

        if (target_k === 0) return 0;
        if (L < target_k) return INF;

        // DP[i][j][state]: min cost selecting j items from first i elements of the range, 
        // where state=1 if the i-th element is selected, state=0 otherwise.
        // i ranges from 0 to L. j ranges from 0 to target_k.
        const DP = Array(L + 1).fill(0).map(() => 
            Array(target_k + 1).fill(0).map(() => [INF, INF])
        );

        // Base case: 0 elements processed, 0 selected, cost 0.
        DP[0][0][0] = 0;

        for (let i = 1; i <= L; i++) {
            const idx = start_idx + i - 1;
            const current_cost = costs[idx];

            for (let j = 0; j <= target_k; j++) {

                // State 0: Current element (idx) is NOT selected.
                // We can transition from either state at i-1.
                DP[i][j][0] = Math.min(DP[i - 1][j][0], DP[i - 1][j][1]);

                // State 1: Current element (idx) IS selected.
                // Must transition from state 0 at i-1, and need j-1 items previously.
                if (j >= 1) {
                    if (DP[i - 1][j - 1][0] !== INF) {
                        DP[i][j][1] = DP[i - 1][j - 1][0] + current_cost;
                    }
                }
            }
        }

        return Math.min(DP[L][target_k][0], DP[L][target_k][1]);
    };

    let min_total_cost = INF;

    // Case 1: Element 0 is NOT selected.
    // Run DP on range [1, n-1] for k peaks.
    let cost1 = solve_linear(1, n - 1, k, C);
    min_total_cost = Math.min(min_total_cost, cost1);

    // Case 2: Element 0 IS selected. (Requires k >= 1, which is true here)
    // Cost starts at C[0]. We need k-1 peaks from range [2, n-2].
    if (k >= 1) {
        let cost2_suffix = INF;

        // If n=3, range is [2, 1], which is empty. L=0.
        if (n === 3) {
            cost2_suffix = 0; // 0 peaks needed from empty set
        } else if (n > 3) {
            // Run DP on range [2, n-2] for k-1 peaks.
            cost2_suffix = solve_linear(2, n - 2, k - 1, C);
        }

        if (cost2_suffix !== INF) {
            min_total_cost = Math.min(min_total_cost, C[0] + cost2_suffix);
        }
    }

    return min_total_cost === INF ? -1 : min_total_cost;
}

