fn solve(nums: Array(Int64), k: Int64) -> Int64 {
    let n = nums.len() as Int64;
    let INF: Int64 = 1_000_000_000_000_000_000;

    if k == 0 {
        return 0;
    }

    // Maximum possible peaks is floor(n/2)
    if k > (n / 2) {
        return -1;
    }

    // 1. Calculate initial costs C_i
    let c: Array(Int64) = Array.new(n);
    for i in 0..<n {
        let i_i64 = i as Int64;

        // Circular indexing helpers
        let prev_idx = ((i_i64 - 1 + n) % n) as Int;
        let next_idx = ((i_i64 + 1) % n) as Int;

        let prev = nums[prev_idx];
        let next = nums[next_idx];

        let required = (prev.max(next) + 1);

        // Calculate cost: max(0, required - nums[i])
        let cost_i = (required - nums[i])
        let c_i = cost_i > 0 ? cost_i : 0;

        c[i] = c_i;
    }

    // 2. Handle N=2 case separately
    if n == 2 {
        // k must be 1 based on initial check
        return c[0].min(c[1]);
    }

    // Solves the linear selection problem: find min cost to select target_k non-adjacent items
    // in the range [start_idx, end_idx] inclusive.
    fn solve_linear(start_idx: Int, end_idx: Int, target_k: Int64, costs: Array(Int64)) -> Int64 {
        if target_k == 0 { return 0; }

        let L = (end_idx - start_idx + 1) as Int64;

        if L < target_k { return INF; }

        let L_int = L as Int;
        let target_k_int = target_k as Int;

        // DP[i][j][state]: min cost selecting j items from first i elements of the range
        // i ranges from 0 to L_int. j ranges from 0 to target_k_int. state=1 (selected), state=0 (not selected).
        var dp: Array(Array(Array(Int64))) = Array.new(L_int + 1);
        for i in 0..L_int {
            dp[i] = Array.new(target_k_int + 1);
            for j in 0..target_k_int {
                dp[i][j] = Array.new(2);
                dp[i][j][0] = INF;
                dp[i][j][1] = INF;
            }
        }

        // Base case: 0 elements processed, 0 selected, cost 0.
        dp[0][0][0] = 0;

        for i in 1..=L_int {
            let idx = start_idx + i - 1;
            let current_cost = costs[idx];

            for j in 0..=target_k_int {

                // State 0: Current element (idx) is NOT selected.
                // Transition from either state at i-1.
                dp[i][j][0] = dp[i-1][j][0].min(dp[i-1][j][1]);

                // State 1: Current element (idx) IS selected.
                // Must transition from state 0 at i-1, and need j-1 items previously.
                if j >= 1 {
                    let prev_cost = dp[i-1][j-1][0];
                    if prev_cost != INF {
                        dp[i][j][1] = prev_cost + current_cost;
                    }
                }
            }
        }

        return dp[L_int][target_k_int][0].min(dp[L_int][target_k_int][1]);
    }

    var min_total_cost: Int64 = INF;

    // Case 1: Element 0 is NOT selected.
    // Run DP on range [1, n-1] for k peaks.
    let cost1 = solve_linear(1, n - 1, k, c);
    min_total_cost = min_total_cost.min(cost1);

    // Case 2: Element 0 IS selected.
    if k >= 1 {
        var cost2_suffix: Int64 = INF;

        // Range for remaining k-1 peaks is [2, n-2].

        // If n=3, range is [2, 1] (empty). L=0.
        if n == 3 {
            // 0 peaks needed from empty set, cost is 0.
            cost2_suffix = 0; 
        } else if n > 3 {
            // Run DP on range [2, n-2] for k-1 peaks.
            cost2_suffix = solve_linear(2, n - 2, k - 1, c);
        } else { // n=2, already handled, but defensively:
            // If n=2, we cannot select 0 AND have an inner range [2, 0]. This path is impossible for n=2 unless k=1 (which is covered by N=2 case).
        }

        if cost2_suffix != INF {
            min_total_cost = min_total_cost.min(c[0] + cost2_suffix);
        }
    }

    return min_total_cost == INF ? -1 : min_total_cost;
}

